from functools import lru_cache

class Solution:
    def minDays(self, n: int) -> int:
        @lru_cache(maxsize=None)
        def dfs(k):
            if k <= 1:
                return k
            return 1 + min(
                k % 2 + dfs(k // 2),
                k % 3 + dfs(k // 3)
            )
        return dfs(n)
```
